patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -8,7 +8,7 @@
   output valid
 );

-  always @(req) begin
+  always @(*) begin
     grant = 8'b0;
     valid = 1'b0;
     if (req[7]) begin

before_code:
module priority_encoder (
  input [7:0] req,
  input [3:0] mask,
  output [7:0] grant,
  output valid
);

  always @(req) begin
    grant = 8'b0;
    valid = 1'b0;
    if (req[7]) begin
      grant = 8'b10000000;
      valid = 1'b1;
    end else if (req[6] & ~mask[6]) begin
      grant = 8'b01000000;
      valid = 1'b1;
    end else if (req[0]) begin
      grant = 8'b00000001;
      valid = 1'b1;
    end
  end

endmodule

after_code:
module priority_encoder (
  input [7:0] req,
  input [3:0] mask,
  output [7:0] grant,
  output valid
);

  always @(*) begin
    grant = 8'b0;
    valid = 1'b0;
    if (req[7]) begin
      grant = 8'b10000000;
      valid = 1'b1;
    end else if (req[6] & ~mask[6]) begin
      grant = 8'b01000000;
      valid = 1'b1;
    end else if (req[0]) begin
      grant = 8'b00000001;
      valid = 1'b1;
    end
  end

endmodule
